/* =========================================================
   WTC Tielt — modern sporty stylesheet
   Palette: black / white / electric blue
   ========================================================= */

:root {
  --blue: #0057ff;
  --blue-600: #0047d6;
  --blue-100: #e6efff;
  --black: #0a0d14;
  --ink: #1a1f2b;
  --ink-2: #4a5160;
  --line: #e6e8ee;
  --bg: #ffffff;
  --bg-alt: #f5f7fb;
  --shadow-sm: 0 1px 2px rgba(10, 13, 20, 0.06), 0 1px 3px rgba(10, 13, 20, 0.04);
  --shadow-md: 0 8px 24px rgba(10, 13, 20, 0.08);
  --shadow-lg: 0 24px 48px rgba(10, 13, 20, 0.18);
  --radius: 14px;
  --radius-sm: 8px;
  --radius-lg: 22px;
  --container: 1180px;
  --display: "Bebas Neue", "Inter", system-ui, sans-serif;
  --body: "Inter", system-ui, -apple-system, "Segoe UI", Roboto, sans-serif;
}

* { box-sizing: border-box; }

html { scroll-behavior: smooth; }

body {
  margin: 0;
  font-family: var(--body);
  color: var(--ink);
  background: var(--bg);
  line-height: 1.6;
  -webkit-font-smoothing: antialiased;
}

img { max-width: 100%; display: block; }

a { color: var(--blue); text-decoration: none; transition: color .15s ease; }
a:hover { color: var(--blue-600); }

h1, h2, h3, h4 {
  margin: 0 0 .5em;
  color: var(--black);
  font-weight: 700;
  letter-spacing: -0.01em;
}
h1 { font-family: var(--display); font-weight: 400; font-size: clamp(2.4rem, 5.4vw, 4.5rem); line-height: 1; letter-spacing: 0; }
h2 { font-family: var(--display); font-weight: 400; font-size: clamp(1.8rem, 3.4vw, 2.8rem); line-height: 1.05; letter-spacing: 0; }
h3 { font-size: 1.15rem; }
h4 { font-size: 1rem; }

p { margin: 0 0 1em; }

.container { max-width: var(--container); margin: 0 auto; padding: 0 24px; }

/* ===========  Buttons  =========== */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: .5rem;
  padding: 14px 24px;
  border-radius: 999px;
  font-weight: 600;
  font-size: 0.95rem;
  letter-spacing: .01em;
  border: 2px solid transparent;
  cursor: pointer;
  transition: transform .12s ease, box-shadow .15s ease, background .15s ease, color .15s ease;
  white-space: nowrap;
}
.btn-primary { background: var(--blue); color: #fff; box-shadow: 0 6px 16px rgba(0, 87, 255, .35); }
.btn-primary:hover { background: var(--blue-600); color: #fff; transform: translateY(-1px); box-shadow: 0 10px 22px rgba(0, 87, 255, .42); }
.btn-ghost { background: transparent; color: #fff; border-color: rgba(255,255,255,.4); }
.btn-ghost:hover { background: rgba(255,255,255,.08); color: #fff; border-color: #fff; }
.btn-outline { background: transparent; color: var(--black); border-color: var(--ink); }
.btn-outline:hover { background: var(--black); color: #fff; }
.btn-sm { padding: 9px 16px; font-size: .85rem; }
.btn-lg { padding: 16px 32px; font-size: 1.05rem; }

/* ===========  Header / Nav  =========== */
.site-header {
  position: sticky;
  top: 0;
  background: rgba(255, 255, 255, .92);
  backdrop-filter: saturate(140%) blur(12px);
  -webkit-backdrop-filter: saturate(140%) blur(12px);
  border-bottom: 1px solid var(--line);
  z-index: 50;
}
.nav-wrap {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  padding: 14px 24px;
  max-width: var(--container);
  margin: 0 auto;
}
.brand { display: flex; align-items: center; gap: 12px; color: var(--black); }
.brand-mark { color: var(--blue); display: inline-flex; }
.brand-text { display: flex; flex-direction: column; line-height: 1; }
.brand-name { font-family: var(--display); font-size: 1.45rem; letter-spacing: .04em; }
.brand-tag { font-size: .68rem; color: var(--ink-2); text-transform: uppercase; letter-spacing: .14em; margin-top: 2px; }

.primary-nav {
  display: flex;
  align-items: center;
  gap: 8px;
}
.primary-nav a {
  padding: 8px 14px;
  border-radius: 8px;
  color: var(--ink);
  font-weight: 500;
  font-size: .95rem;
}
.primary-nav a:hover { color: var(--black); background: var(--bg-alt); }
.primary-nav a.active:not(.btn) { color: var(--blue); }
.primary-nav a.active:not(.btn)::after { display: none; }

.nav-toggle {
  display: none;
  background: transparent;
  border: 0;
  width: 40px;
  height: 40px;
  cursor: pointer;
  padding: 0;
  border-radius: 8px;
}
.nav-toggle span {
  display: block;
  width: 22px;
  height: 2px;
  background: var(--black);
  margin: 5px auto;
  border-radius: 2px;
  transition: transform .2s ease, opacity .2s ease;
}
.nav-toggle[aria-expanded="true"] span:nth-child(1) { transform: translateY(7px) rotate(45deg); }
.nav-toggle[aria-expanded="true"] span:nth-child(2) { opacity: 0; }
.nav-toggle[aria-expanded="true"] span:nth-child(3) { transform: translateY(-7px) rotate(-45deg); }

/* ===========  Hero  =========== */
.hero {
  position: relative;
  color: #fff;
  padding: 120px 0 100px;
  overflow: hidden;
  isolation: isolate;
}
.hero-bg {
  position: absolute;
  inset: 0;
  z-index: -1;
  background:
    radial-gradient(1200px 600px at 80% -10%, rgba(0, 87, 255, .55), transparent 60%),
    radial-gradient(900px 500px at -10% 110%, rgba(0, 87, 255, .35), transparent 55%),
    linear-gradient(150deg, #0a0d14 0%, #0f1424 55%, #0a0d14 100%);
}
.hero-bg::after {
  content: "";
  position: absolute; inset: 0;
  background-image:
    repeating-linear-gradient(45deg, rgba(255,255,255,.03) 0 1px, transparent 1px 14px),
    repeating-linear-gradient(-45deg, rgba(255,255,255,.025) 0 1px, transparent 1px 14px);
  mix-blend-mode: overlay;
}
.hero-inner { position: relative; max-width: 820px; }
.hero h1 { color: #fff; }
.hero .lead { font-size: 1.2rem; color: rgba(255,255,255,.85); max-width: 640px; margin-top: 1.2rem; }
.hero-cta { display: flex; flex-wrap: wrap; gap: 12px; margin-top: 32px; }

.eyebrow {
  display: inline-block;
  font-size: .78rem;
  font-weight: 600;
  letter-spacing: .18em;
  text-transform: uppercase;
  color: var(--blue);
  margin: 0 0 14px;
  padding: 6px 12px;
  background: var(--blue-100);
  border-radius: 999px;
}
.hero .eyebrow { color: #b6c8ff; background: rgba(0, 87, 255, .18); }

.accent { color: var(--blue); }
.hero .accent { color: #6da5ff; }

.hero-stats {
  display: flex;
  gap: 36px;
  list-style: none;
  padding: 0;
  margin: 56px 0 0;
  flex-wrap: wrap;
}
.hero-stats li { display: flex; flex-direction: column; gap: 4px; }
.stat-num { font-family: var(--display); font-size: 2.6rem; line-height: 1; color: #fff; }
.stat-label { font-size: .8rem; color: rgba(255,255,255,.65); text-transform: uppercase; letter-spacing: .16em; }

/* ===========  Page hero (inner pages)  =========== */
.page-hero {
  background: linear-gradient(180deg, var(--bg-alt) 0%, var(--bg) 100%);
  padding: 80px 0 56px;
  border-bottom: 1px solid var(--line);
}
.page-hero h1 { max-width: 16ch; }
.page-hero .lead { font-size: 1.15rem; color: var(--ink-2); max-width: 640px; }

/* ===========  Sections  =========== */
.section { padding: 80px 0; }
.section-alt { background: var(--bg-alt); }

.section-head { margin-bottom: 40px; max-width: 720px; }
.section-head.between { display: flex; align-items: end; justify-content: space-between; gap: 24px; max-width: none; flex-wrap: wrap; }
.lead { font-size: 1.1rem; color: var(--ink-2); }

/* ===========  Grid  =========== */
.grid { display: grid; gap: 24px; }
.grid-3 { grid-template-columns: repeat(3, 1fr); }
.grid-4 { grid-template-columns: repeat(4, 1fr); }

.two-col {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 56px;
  align-items: start;
}

/* ===========  Card  =========== */
.card {
  background: #fff;
  border: 1px solid var(--line);
  border-radius: var(--radius);
  padding: 28px;
  transition: transform .15s ease, box-shadow .15s ease, border-color .15s ease;
}
.card:hover { transform: translateY(-3px); box-shadow: var(--shadow-md); border-color: transparent; }
.card-icon { font-size: 1.8rem; margin-bottom: 12px; }

/* ===========  Ride preview list (home) =========== */
.ride-list {
  background: #fff;
  border: 1px solid var(--line);
  border-radius: var(--radius);
  padding: 8px;
}
.ride-row {
  display: flex;
  align-items: center;
  gap: 18px;
  padding: 18px;
  border-radius: var(--radius-sm);
  border-bottom: 1px solid var(--line);
}
.ride-row:last-child { border-bottom: 0; }
.ride-day {
  font-family: var(--display);
  font-size: 1.6rem;
  background: var(--black);
  color: #fff;
  padding: 12px 16px;
  border-radius: 12px;
  letter-spacing: .04em;
  min-width: 64px;
  text-align: center;
}
.ride-meta h4 { margin: 0; }
.ride-meta p { margin: 0; color: var(--ink-2); font-size: .9rem; }

/* ===========  Events =========== */
.event-card {
  background: #fff;
  border: 1px solid var(--line);
  border-radius: var(--radius);
  padding: 24px;
  transition: transform .15s ease, box-shadow .15s ease;
}
.event-card:hover { transform: translateY(-3px); box-shadow: var(--shadow-md); }
.event-date {
  display: inline-flex;
  flex-direction: column;
  align-items: center;
  background: var(--blue);
  color: #fff;
  padding: 6px 12px 8px;
  border-radius: 10px;
  font-weight: 600;
  font-size: .72rem;
  letter-spacing: .14em;
  text-transform: uppercase;
  line-height: 1;
  margin-bottom: 14px;
}
.event-date span {
  font-family: var(--display);
  font-size: 1.6rem;
  letter-spacing: 0;
  font-weight: 400;
  line-height: 1;
  margin-bottom: 2px;
}
.event-date.big { padding: 10px 16px 12px; min-width: 72px; }
.event-date.big span { font-size: 2rem; }

.event-list { display: flex; flex-direction: column; gap: 12px; }
.event-row {
  display: grid;
  grid-template-columns: auto 1fr auto;
  gap: 24px;
  align-items: center;
  padding: 22px 26px;
  background: #fff;
  border: 1px solid var(--line);
  border-radius: var(--radius);
  transition: border-color .15s ease, box-shadow .15s ease, transform .15s ease;
}
.event-row:hover { border-color: var(--blue); box-shadow: var(--shadow-md); transform: translateX(4px); }
.event-body h3 { margin-bottom: 4px; }
.event-body p { margin: 0; }
.event-body p.muted { font-size: .85rem; margin-bottom: 4px; }

.badge {
  font-size: .72rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: .12em;
  padding: 6px 12px;
  border-radius: 999px;
}
.badge-blue { background: var(--blue-100); color: var(--blue-600); }
.badge-yellow { background: #fff5d6; color: #92670d; }
.badge-green { background: #def7e7; color: #1a6e3b; }

/* ===========  CTA banner =========== */
.cta-banner {
  background: var(--black);
  color: #fff;
  padding: 56px 0;
  margin-top: 0;
}
.cta-inner {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 24px;
  flex-wrap: wrap;
}
.cta-inner h2 { color: #fff; margin: 0 0 6px; }
.cta-inner p { margin: 0; color: rgba(255,255,255,.75); }

/* ===========  About: members =========== */
.member-card {
  background: #fff;
  border: 1px solid var(--line);
  border-radius: var(--radius);
  padding: 24px;
  text-align: center;
}
.member-card .role { color: var(--blue); font-size: .85rem; font-weight: 600; text-transform: uppercase; letter-spacing: .12em; margin: 0; }
.avatar {
  width: 80px; height: 80px;
  border-radius: 50%;
  margin: 0 auto 16px;
  display: grid;
  place-items: center;
  font-family: var(--display);
  font-size: 1.6rem;
  color: #fff;
  background: var(--black);
  letter-spacing: .04em;
}
.avatar-1 { background: linear-gradient(135deg, var(--blue), #6da5ff); }
.avatar-2 { background: linear-gradient(135deg, var(--black), #2a3247); }
.avatar-3 { background: linear-gradient(135deg, var(--blue-600), var(--blue)); }
.avatar-4 { background: linear-gradient(135deg, #1a1f2b, #4a5160); }

.check-list { list-style: none; padding: 0; margin: 0; }
.check-list li {
  position: relative;
  padding: 8px 0 8px 28px;
  border-bottom: 1px solid var(--line);
}
.check-list li:last-child { border-bottom: 0; }
.check-list li::before {
  content: "";
  position: absolute;
  left: 0; top: 14px;
  width: 16px; height: 16px;
  background: var(--blue-100);
  border-radius: 50%;
}
.check-list li::after {
  content: "";
  position: absolute;
  left: 4px; top: 17px;
  width: 8px; height: 4px;
  border-left: 2px solid var(--blue);
  border-bottom: 2px solid var(--blue);
  transform: rotate(-45deg);
}

/* ===========  Timeline =========== */
.timeline {
  list-style: none;
  margin: 0;
  padding: 0;
  position: relative;
}
.timeline::before {
  content: "";
  position: absolute;
  left: 88px; top: 8px; bottom: 8px;
  width: 2px;
  background: var(--line);
}
.timeline li {
  display: grid;
  grid-template-columns: 96px 1fr;
  gap: 24px;
  padding: 14px 0;
  position: relative;
}
.timeline li::before {
  content: "";
  position: absolute;
  left: 84px; top: 22px;
  width: 10px; height: 10px;
  background: var(--blue);
  border: 3px solid #fff;
  border-radius: 50%;
  box-shadow: 0 0 0 1px var(--blue);
}
.t-year {
  font-family: var(--display);
  font-size: 1.4rem;
  color: var(--ink-2);
  letter-spacing: .04em;
}
.timeline h4 { margin: 0 0 4px; }
.timeline p { margin: 0; color: var(--ink-2); }

/* ===========  Rides page =========== */
.level-card {
  background: #fff;
  border: 1px solid var(--line);
  border-radius: var(--radius);
  padding: 28px;
  position: relative;
  overflow: hidden;
}
.level-card::before {
  content: "";
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 4px;
  background: var(--blue);
}
.level-a::before { background: var(--blue); }
.level-b::before { background: var(--black); }
.level-c::before { background: linear-gradient(90deg, var(--blue), var(--black)); }

.level-tag {
  display: inline-block;
  font-family: var(--display);
  font-size: 1.1rem;
  letter-spacing: .08em;
  background: var(--bg-alt);
  padding: 6px 14px;
  border-radius: 8px;
  margin-bottom: 16px;
}
.level-pace {
  font-family: var(--display);
  font-size: 1.8rem;
  color: var(--blue);
  margin: 8px 0 16px;
  letter-spacing: 0;
}

.schedule-table {
  background: #fff;
  border: 1px solid var(--line);
  border-radius: var(--radius);
  overflow: hidden;
}
.schedule-row {
  display: grid;
  grid-template-columns: 1.2fr 1fr 1fr 1.2fr 1fr;
  gap: 16px;
  padding: 16px 20px;
  border-bottom: 1px solid var(--line);
}
.schedule-row:last-child { border-bottom: 0; }
.schedule-row.schedule-head {
  background: var(--bg-alt);
  font-weight: 600;
  font-size: .8rem;
  text-transform: uppercase;
  letter-spacing: .12em;
  color: var(--ink-2);
}

/* ===========  Gallery =========== */
.gallery-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  grid-auto-rows: 180px;
  gap: 16px;
}
.g-item {
  margin: 0;
  border-radius: var(--radius);
  overflow: hidden;
  position: relative;
  cursor: zoom-in;
  background: var(--bg-alt);
}
.g-tall { grid-row: span 2; }
.g-wide { grid-column: span 2; }
.g-img {
  width: 100%;
  height: 100%;
  background-size: cover;
  background-position: center;
  transition: transform .4s ease;
}
.g-item:hover .g-img { transform: scale(1.04); }
.g-item figcaption {
  position: absolute;
  left: 12px; right: 12px; bottom: 12px;
  background: rgba(10, 13, 20, .82);
  color: #fff;
  padding: 6px 10px;
  border-radius: 8px;
  font-size: .8rem;
  font-weight: 500;
  opacity: 0;
  transform: translateY(6px);
  transition: opacity .2s ease, transform .2s ease;
}
.g-item:hover figcaption { opacity: 1; transform: none; }

/* SVG-data placeholder gradients (no external images required) */
.g-1 { background-image: linear-gradient(135deg, #0057ff 0%, #001f7a 100%); }
.g-2 { background-image: linear-gradient(135deg, #0a0d14 0%, #4a5160 100%); }
.g-3 { background-image: linear-gradient(135deg, #6da5ff 0%, #0057ff 100%); }
.g-4 { background-image: linear-gradient(135deg, #0047d6 0%, #0a0d14 100%); }
.g-5 { background-image: linear-gradient(135deg, #1a1f2b 0%, #0057ff 100%); }
.g-6 { background-image: linear-gradient(135deg, #0057ff 0%, #6da5ff 100%); }
.g-7 { background-image: linear-gradient(135deg, #4a5160 0%, #0a0d14 100%); }
.g-8 { background-image: linear-gradient(135deg, #0a0d14 0%, #0057ff 100%); }
.g-9 { background-image: linear-gradient(135deg, #6da5ff 0%, #0a0d14 100%); }

/* ===========  Forms =========== */
.form { display: grid; gap: 16px; }
.field { display: grid; gap: 6px; }
.field label { font-weight: 600; font-size: .9rem; color: var(--ink); }
.field input,
.field select,
.field textarea {
  width: 100%;
  padding: 12px 14px;
  border: 1.5px solid var(--line);
  border-radius: var(--radius-sm);
  font: inherit;
  color: var(--ink);
  background: #fff;
  transition: border-color .15s ease, box-shadow .15s ease;
}
.field input:focus,
.field select:focus,
.field textarea:focus {
  outline: none;
  border-color: var(--blue);
  box-shadow: 0 0 0 4px rgba(0, 87, 255, .15);
}
.form .btn { justify-self: start; }

.contact-side {
  background: #fff;
  border: 1px solid var(--line);
  border-radius: var(--radius);
  padding: 28px;
}
.contact-list { list-style: none; padding: 0; margin: 0; }
.contact-list li {
  display: flex;
  gap: 14px;
  padding: 14px 0;
  border-bottom: 1px solid var(--line);
}
.contact-list li:last-child { border-bottom: 0; }
.contact-list .ci {
  width: 40px; height: 40px;
  background: var(--blue-100);
  border-radius: 10px;
  display: grid; place-items: center;
  font-size: 1.2rem;
  flex-shrink: 0;
}

/* ===========  FAQ =========== */
.faq { display: grid; gap: 12px; max-width: 760px; }
.faq details {
  background: #fff;
  border: 1px solid var(--line);
  border-radius: var(--radius);
  padding: 18px 22px;
  transition: border-color .15s ease;
}
.faq details[open] { border-color: var(--blue); }
.faq summary {
  cursor: pointer;
  font-weight: 600;
  list-style: none;
  position: relative;
  padding-right: 28px;
}
.faq summary::-webkit-details-marker { display: none; }
.faq summary::after {
  content: "+";
  position: absolute;
  right: 0; top: 50%;
  transform: translateY(-50%);
  font-size: 1.4rem;
  color: var(--blue);
  font-weight: 400;
  transition: transform .15s ease;
}
.faq details[open] summary::after { content: "−"; }
.faq p { margin: 12px 0 0; color: var(--ink-2); }

/* ===========  Footer =========== */
.site-footer {
  background: var(--black);
  color: rgba(255,255,255,.75);
  padding: 56px 0 24px;
  margin-top: 80px;
}
.brand-footer .brand-name { color: #fff; }
.brand-footer .brand-mark { color: var(--blue); }
.footer-grid {
  display: grid;
  grid-template-columns: 1.4fr 1fr 1fr 1fr;
  gap: 36px;
  padding-bottom: 32px;
}
.footer-grid h4 { color: #fff; font-size: .9rem; text-transform: uppercase; letter-spacing: .12em; margin-bottom: 14px; }
.footer-links { list-style: none; padding: 0; margin: 0; }
.footer-links li { margin: 6px 0; }
.footer-links a { color: rgba(255,255,255,.75); }
.footer-links a:hover { color: #fff; }
.footer-bottom {
  border-top: 1px solid rgba(255,255,255,.1);
  padding-top: 20px;
  font-size: .85rem;
  color: rgba(255,255,255,.55);
}
.footer-bottom p { margin: 0; }

/* ===========  Utility =========== */
.muted { color: var(--ink-2); }
.small { font-size: .85rem; }
.center { text-align: center; }
.link-arrow { font-weight: 600; }

/* ===========  Helper for typography color on dark sections ===========*/
.cta-banner .eyebrow { background: rgba(255,255,255,.1); color: #fff; }

/* =========================================================
   Responsive
   ========================================================= */
@media (max-width: 920px) {
  .grid-3, .grid-4 { grid-template-columns: repeat(2, 1fr); }
  .two-col { grid-template-columns: 1fr; gap: 32px; }
  .section { padding: 64px 0; }
  .hero { padding: 80px 0 70px; }
  .footer-grid { grid-template-columns: 1fr 1fr; }
  .schedule-row { grid-template-columns: 1fr 1fr; font-size: .9rem; }
  .schedule-row.schedule-head { display: none; }
  .schedule-row > div::before {
    content: attr(role);
    /* Keeping accessibility but using CSS-only labels */
  }
  .gallery-grid { grid-template-columns: repeat(2, 1fr); grid-auto-rows: 160px; }
  .g-wide { grid-column: span 2; }
  .timeline::before { left: 40px; }
  .timeline li { grid-template-columns: 56px 1fr; gap: 16px; }
  .timeline li::before { left: 36px; }
  .t-year { font-size: 1.1rem; }
  .event-row { grid-template-columns: auto 1fr; }
  .event-row .badge { grid-column: 2; justify-self: start; }
}

@media (max-width: 700px) {
  .nav-toggle { display: inline-block; }
  .primary-nav {
    position: absolute;
    top: 70px;
    left: 0; right: 0;
    background: #fff;
    border-bottom: 1px solid var(--line);
    flex-direction: column;
    align-items: stretch;
    padding: 14px 24px 22px;
    gap: 4px;
    transform: translateY(-12px);
    opacity: 0;
    pointer-events: none;
    transition: opacity .15s ease, transform .15s ease;
  }
  .primary-nav.is-open { transform: none; opacity: 1; pointer-events: auto; }
  .primary-nav a { padding: 12px 14px; }
  .primary-nav .btn { margin-top: 8px; text-align: center; }
  .grid-3, .grid-4 { grid-template-columns: 1fr; }
  .footer-grid { grid-template-columns: 1fr; gap: 28px; }
  .hero-stats { gap: 24px; }
  .stat-num { font-size: 2.1rem; }
  .cta-inner { flex-direction: column; align-items: flex-start; }
  .section-head.between { flex-direction: column; align-items: flex-start; }
  .gallery-grid { grid-template-columns: 1fr; grid-auto-rows: 200px; }
  .g-tall, .g-wide { grid-column: auto; grid-row: auto; }
}

@media (prefers-reduced-motion: reduce) {
  * { transition: none !important; animation: none !important; }
  html { scroll-behavior: auto; }
}

